const SUPABASE_URL = 'https://faklxfakgzkpkbxfihzh.supabase.co';
const SUPABASE_API_KEY = 'sb_publishable_HsIkelEZaIr0VauiB3GgIQ_59XJRoWc';

const input = $input.first().json;
const userId = input.body?.user_id || input.user_id || '';

let recipient_email = 'eric@agileadtesting.com';
let bcc_email = '';

try {
  const userFilter = userId ? `&user_id=eq.${userId}` : '';
  const rows = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/app_config_v2?key=in.(recipient_email,bcc_email)&select=key,value${userFilter}`,
    headers: { 'apikey': SUPABASE_API_KEY, 'Authorization': `Bearer ${SUPABASE_API_KEY}` }
  });
  for (const row of rows) {
    if (row.key === 'recipient_email') recipient_email = row.value;
    if (row.key === 'bcc_email') bcc_email = row.value;
  }
} catch (e) {
  // fallback to defaults above
}

return [{ json: { ...input, recipient_email, bcc_email } }];

const input = $input.first().json;
const userId = input.body?.user_id || input.user_id || '';
const msg = (input.chatInput || input.body?.user_message_request || '').toLowerCase();
const original = input.chatInput || input.body?.user_message_request || '';

// NUMBER REFERENCE — user picks an item from a previous list (e.g. "1", "show me 3", "#7", "the first one")
const ordinals = { 'first': '1', 'second': '2', 'third': '3', 'fourth': '4', 'fifth': '5', 'sixth': '6', 'seventh': '7', 'eighth': '8', 'ninth': '9', 'tenth': '10' };
const numberMatch = msg.trim().match(/^#?(\d{1,2})$/) || msg.trim().match(/^(?:show\s+(?:me\s+)?|get\s+|open\s+|select\s+|pick\s+)?#?(\d{1,2})\s*$/) || msg.trim().match(/^(?:show\s+(?:me\s+)?|get\s+|open\s+|select\s+|pick\s+)?(?:the\s+)?(first|second|third|fourth|fifth|sixth|seventh|eighth|ninth|tenth)(?:\s+one)?\s*$/);
if (numberMatch) {
  const num = numberMatch[1] && /^\d+$/.test(numberMatch[1]) ? numberMatch[1] : ordinals[numberMatch[1]] || numberMatch[1];
  return [{ json: { ...input, user_id: userId, originalUserPrompt: original, isAsyncOp, isWebhookTrigger, chatInput: original + ' [LIST SELECTION: The user is selecting item #' + num + ' from the most recent numbered list in conversation history. Look at the last list you showed the user (outlines, projects, chapters, drafts, story arcs, etc). Find item #' + num + ' by its number. Then call the appropriate tool to retrieve that specific item by name/title. For outlines: call retrieve_content with the outline title. For drafts/published content: call manage_library. For story arcs: call retrieve_content with content_type=story_arc. For chapters: call retrieve_content with the chapter title. IMPORTANT: Do NOT ask the user to clarify — find the item from conversation history and retrieve it immediately.]' } }];
}

// RETRIEVE ops — content retrieval (must be checked BEFORE brainstorm to catch revert/version/list)
const isRetrieveOp = /\b(retrieve|pull\s+up|fetch\s+my|find\s+my|get\s+my\s+(draft|chapter|story|blog|newsletter|article|report)|chapters?\s+from|all\s+chapters?\s+(from|of|in)|list\s+(story\s+)?arcs?|what\s+story\s+arcs?|available\s+arcs?|(list|show|all)\s+(my\s+)?outlines?|outline\s+(list|version|history)|revert.{0,20}outline|restore.{0,20}outline|outline.{0,20}version)/.test(msg);

// EDIT OUTLINE ops — small targeted changes to an existing outline (ages, names, descriptions)
const isEditOutlineOp = !isRetrieveOp && /\b(make\s+\w+.{0,20}(years?\s+old|age\s+\d)|change.{0,20}(age|name|title|role|description)|rename\s+(chapter|character)|update.{0,20}(age|description|premise|role)|using\s+this\s+outline.{0,20}(make|change|update|fix|set)|fix.{0,20}(chapter|brief|inconsisten|outline)|\bcharacter\s+role\s+change|\d+\s+years?\s+old)/.test(msg) && !/\b(add.{0,10}chapter|new\s+chapter|change.{0,15}(arc|structure|timeline)|restructure|expand|brainstorm|rework)/.test(msg);

// BRAINSTORM ops — story planning, outline expansion, character development (checked AFTER retrieve and edit)
const isBrainstormOp = !isRetrieveOp && !isEditOutlineOp && /\b(brainstorm|expand.{0,25}outline|add.{0,15}(more\s+)?chapter|develop.{0,20}character|revis(e|ing).{0,20}(outline|story\s+arc)|rework.{0,20}(outline|story)|outline\s+(a|the|my|this)\s+\w|plan\s+(a|the|my)\s+(novel|book|story)|create\s+(a|the|my)\s+(outline|book))/.test(msg);

// PROJECT LIST ops — must be before isLibraryOp to avoid misrouting
const isProjectOp = /\b(list\s+(my\s+|all\s+)?projects?|my\s+projects?|all\s+projects?|what\s+projects?|show.{0,15}projects?)/.test(msg);

// LIBRARY ops — content status management only
const isLibraryOp = /\b(approve|unschedule|unpublish|publish|reject|schedule|list\s+(all|draft|published|scheduled|approved|rejected)|content\s+librar|my\s+(draft|post|content|article|newsletter|chapter|stor)|show\s+(me\s+)?(my|what|all)|what.{0,20}(written|published|draft|created)|show\s+all|see\s+all|all\s+content|all\s+(my\s+)?(posts?|draft|items?|articles?)|remove.{0,20}(schedule|publish)|cancel.{0,20}schedule|version\s+histor|list\s+version|get\s+version|show.{0,15}version|version.{0,10}(this|that|it))/.test(msg);

// WRITING ops — trigger writing sub-workflows
const isWritingOp = /\b(write\s+(a|the|my|an)\s+(blog|newsletter|short\s+stor|chapter|article)|write\s+chapter)/.test(msg);
const isWebhookTrigger = !!input.body;
const isAsyncOp = !isRetrieveOp && !isEditOutlineOp && !isProjectOp && !isLibraryOp && (isWritingOp || isBrainstormOp || /\b(repurpose|social\s+(media|post)|cover\s+art|research\s+report|email.{0,15}report)/.test(msg));

if (isRetrieveOp) {
  return [{ json: { ...input, user_id: userId, originalUserPrompt: original, isAsyncOp, isWebhookTrigger, chatInput: '[TOOL OVERRIDE — retrieve_content] You MUST call retrieve_content RIGHT NOW. This is NOT optional. Do NOT call manage_library. Do NOT call brainstorm_story. You have NO ability to list or retrieve content yourself — only the retrieve_content tool can query the database. If you respond without calling retrieve_content, the user will receive nothing. Pass the FULL user message as search_term (do not extract keywords or shorten it). After the tool returns, relay its result verbatim.\n\n' + original } }];
}
if (isEditOutlineOp) {
  return [{ json: { ...input, user_id: userId, originalUserPrompt: original, isAsyncOp, isWebhookTrigger, chatInput: '[TOOL OVERRIDE — edit_outline] You MUST call edit_outline RIGHT NOW. This is NOT optional. You have NO ability to modify outlines yourself — only the edit_outline tool can read, modify, and save outlines in the database. Even for small changes (ages, names, roles, single details), you MUST call edit_outline. If you respond without calling edit_outline, the outline will NOT be updated and the user will receive false information. Extract project_title and edit_instructions from the request below. Do NOT call brainstorm_story. After the tool returns, relay its result verbatim.\n\n' + original } }];
}
if (isBrainstormOp) {
  return [{ json: { ...input, user_id: userId, originalUserPrompt: original, isAsyncOp, isWebhookTrigger, chatInput: '[TOOL OVERRIDE — brainstorm_story] You MUST call brainstorm_story RIGHT NOW. This is NOT optional. You have NO ability to modify outlines yourself — only the brainstorm_story tool can read, modify, and save outlines in the database. Even for small changes (ages, names, single details), you MUST call brainstorm_story. If you respond without calling brainstorm_story, the outline will NOT be updated and the user will receive false information. Do NOT call write_short_story or write_chapter. Extract project details from the request below. After the tool returns, relay its result verbatim.\n\n' + original } }];
}
if (isProjectOp) {
  return [{ json: { ...input, user_id: userId, originalUserPrompt: original, isAsyncOp, isWebhookTrigger, chatInput: original + ' [MANDATORY: Call manage_library with operation=list_projects RIGHT NOW. Do not respond with any text before calling the tool.]' } }];
}
if (isLibraryOp) {
  return [{ json: { ...input, user_id: userId, originalUserPrompt: original, isAsyncOp, isWebhookTrigger, chatInput: original + ' [MANDATORY: Call manage_library with content_title from my message right now. Do not respond with any text before calling the tool.]' } }];
}
if (isWritingOp) {
  const usesOutline = /\b(using\s+(this|the|my|that)\s+(outline|brainstorm)|from\s+(the|my|that)\s+outline|we\s+brainstormed|story\s+outline)/.test(msg);
  const outlineHint = usesOutline ? ' IMPORTANT: The user is referencing a previously brainstormed outline. You MUST pass the project_title from the brainstorm session so the workflow loads the stored outline. Do NOT paraphrase the premise from memory.' : '';
  return [{ json: { ...input, user_id: userId, originalUserPrompt: original, isAsyncOp, isWebhookTrigger, chatInput: original + ' [MANDATORY: Call the appropriate writing tool (write_blog_post, write_newsletter, write_short_story, or write_chapter) right now. Do NOT write content in chat. Do not respond before calling the tool.' + outlineHint + ']' } }];
}

return [{ json: { ...input, user_id: userId, originalUserPrompt: original, isAsyncOp, isWebhookTrigger } }];

